return videoUrls.map(url => ({ json: { url } }));

const data = $input.first().json;
const clips = data.clips || [];
const job = data.job || {};

const summary = `✅ AutoClip selesai!\n` +
  `Job: ${job.id?.slice(0,8)}\n` +
  `Clip: ${clips.length} buah\n` +
  `Source: ${job.url}\n` +
  `n8n: ${data.n8n?.notified ? 'Upload ke GDrive dimulai' : 'Tersedia lokal'}`;

return [{ json: { summary, clipCount: clips.length, jobId: job.id } }];

const data = $input.first().json;
const error = data.error || {};

return [{ json: { 
  summary: `❌ AutoClip gagal: ${error.message || 'Unknown error'}`,
  errorCode: error.code
} }];
